from typing import List

def solve(nums: List[int], k: int) -> int:
    prefix_mod = [0] * (len(nums) + 1)
    for i in range(len(nums)):
        prefix_mod[i + 1] = (prefix_mod[i] + nums[i]) % k

    mod_count = [0] * k
    for mod in prefix_mod:
        mod_count[mod] += 1

    for i in range(k):
        if mod_count[i] > 0:
            mod_count[i] = 1

    total = 0
    for i in range(k):
        total += mod_count[i] * i

    return total
